from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""
    clauses: list[str] = []
    for t in triples:
        # Form a possessive subject (e.g., "James' height" vs "James's height")
        if t.subject.endswith("s"):
            subj_possessive = f"{t.subject}'"
        else:
            subj_possessive = f"{t.subject}'s"
        clauses.append(f"{subj_possessive} {t.predicate} is {t.object}")
    if len(clauses) == 1:
        return clauses[0] + "."
    # Join with commas and an 'and' before the final clause for fluency
    return ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

